"use client"

import * as React from "react"

import { EvaluationCardDrawer } from "./evaluation-card-drawer"
import { EvaluationCardPreview } from "./evaluation-card-preview"
import type { EvaluationCardProps } from "./types"

export function EvaluationCard({
  data,
  ctaText,
  drawerHeading,
  isMobile = false,
  className,
}: EvaluationCardProps) {
  const [open, setOpen] = React.useState(false)
  const resolvedDirection = isMobile ? "bottom" : "right"

  return (
    <>
      <EvaluationCardPreview data={data} ctaText={ctaText} className={className} onCtaClick={() => setOpen(true)} />
      <EvaluationCardDrawer
        data={data}
        heading={drawerHeading}
        open={open}
        onOpenChange={setOpen}
        resolvedDirection={resolvedDirection}
      />
    </>
  )
}

export type {
  EvaluationCardProps,
  EvaluationCardData,
  EvaluationDetail,
  EvaluationItem,
  EvaluationStatus,
} from "./types"

import { CardCtaButton } from "../shared/card-cta-button"
import type { EvaluationCardProps, EvaluationStatus } from "./types"
import { EvaluationSummaryRow } from "./evaluation-summary-row"

const cn = (...classes: Array<string | false | null | undefined>) => classes.filter(Boolean).join(" ")

type EvaluationCardPreviewProps = Pick<EvaluationCardProps, "data" | "ctaText" | "className"> & {
  onCtaClick: () => void
}

type StatusPillProps = {
  status: EvaluationStatus
  score?: number | null
  className?: string
  completedTemplate?: "score-only" | "cgpa" | "cgpa-out-of-10"
}

const STATUS_STYLES: Record<EvaluationStatus, string> = {
  upcoming: "bg-[#EBF5FF] text-[#3F83F8]",
  not_attempted: "bg-[#FDF2F2] text-[#F05252]",
  score_pending: "bg-[#FDFDEA] text-[#C27803]",
  completed: "bg-[#F3FAF7] text-[#0E9F6E]",
}

function toLabel(value: EvaluationStatus) {
  return value
    .replace(/_/g, " ")
    .replace(/\b\w/g, (char) => char.toUpperCase())
}

function formatDecimal(value: number) {
  return Number.isInteger(value) ? value.toString() : value.toFixed(2).replace(/\.?0+$/, "")
}

function StatusPill({
  status,
  score,
  className,
  completedTemplate = "score-only",
}: StatusPillProps) {
  const text =
    status === "completed" && typeof score === "number"
      ? completedTemplate === "cgpa-out-of-10"
        ? `${formatDecimal(score)} / 10 (CGPA)`
        : completedTemplate === "cgpa"
          ? `${formatDecimal(score)} CGPA`
          : formatDecimal(score)
      : toLabel(status)

  return (
    <span
      className={cn(
        "inline-flex w-fit items-center rounded-[999px] px-2 py-1 text-[11px] font-[500] capitalize",
        STATUS_STYLES[status],
        className,
      )}
    >
      {text}
    </span>
  )
}

export function EvaluationCardPreview({ data, ctaText, className, onCtaClick }: EvaluationCardPreviewProps) {
  return (
    <div
      className={cn(
        "font-poppins w-full max-w-[760px] rounded-[12px] border border-[#E5E7EB] bg-white p-4",
        className,
      )}
    >
      <div className="space-y-2">
        {data.evaluationDetails.map((detail) => (
          <div
            key={detail.id}
            className="overflow-hidden rounded-[8px] border border-[#E5E7EB]"
          >
            <EvaluationSummaryRow
              title={detail.title}
              finalWeightage={detail.finalWeightage}
              finalStatus={detail.finalStatus}
              finalScore={detail.finalScore}
              showChevron={false}
            />
          </div>
        ))}
      </div>

      <div className="mt-4 flex justify-end">
        <CardCtaButton text={ctaText} onClick={onCtaClick} theme="purple" />
      </div>
    </div>
  )
}

export { StatusPill, formatDecimal }

"use client";

import * as Dialog from "@radix-ui/react-dialog";
import {
  CalendarDots,
  ChartBar,
  CheckCircle,
  CheckSquareOffset,
  ClipboardText,
  FileText,
  X,
} from "@phosphor-icons/react";
import * as React from "react";

import type { EvaluationCardData } from "./types";
import { RichContent } from "./rich-content";
import { formatDecimal } from "./evaluation-card-preview";
import { EvaluationSummaryRow } from "./evaluation-summary-row";

const cn = (...classes: Array<string | false | null | undefined>) => classes.filter(Boolean).join(" ");

type EvaluationCardDrawerProps = {
  data: EvaluationCardData;
  heading: string;
  open: boolean;
  onOpenChange: (open: boolean) => void;
  resolvedDirection: "right" | "bottom";
};

function formatDateTime(value: string) {
  const parsed = new Date(value);
  if (Number.isNaN(parsed.getTime())) return value;
  return parsed.toLocaleString("en-GB", {
    day: "2-digit",
    month: "short",
    year: "numeric",
    hour: "2-digit",
    minute: "2-digit",
    hour12: true,
  });
}

function toScoreLabel(
  status: "upcoming" | "not_attempted" | "score_pending" | "completed",
  score: number | null,
) {
  if (status !== "completed" || typeof score !== "number") {
    return status
      .replace(/_/g, " ")
      .replace(/\b\w/g, (char) => char.toUpperCase());
  }
  return `${formatDecimal(score)} CGPA`;
}

type StatBoxProps = {
  title: string;
  value: string | number;
  valueSuffix?: string;
  icon: React.ReactNode;
};

function StatBox({ title, value, valueSuffix, icon }: StatBoxProps) {
  return (
    <div className="flex gap-[12px] rounded-[8px] border border-[#F3F4F6] bg-[#F9FAFB] p-[12px]">
      <span className="inline-flex size-10 shrink-0 items-center justify-center rounded-[8px] bg-white text-[#0694A2]">
        {icon}
      </span>
      <div className="min-w-0">
        <p className="text-[12px] font-[500] leading-[16px] text-[#6B7280]">
          {title}
        </p>
        <p className="mt-[6px] text-[24px] font-[600] leading-[32px] text-[#111928]">
          {value}
          {valueSuffix ? (
            <span className="ml-1 text-[14px] font-[600] leading-[20px] text-[#111928]">
              {valueSuffix}
            </span>
          ) : null}
        </p>
      </div>
    </div>
  );
}

export function EvaluationCardDrawer({
  data,
  heading,
  open,
  onOpenChange,
  resolvedDirection,
}: EvaluationCardDrawerProps) {
  const [openAccordions, setOpenAccordions] = React.useState<
    Record<string, boolean>
  >(() =>
    data.evaluationDetails.length > 0
      ? { [data.evaluationDetails[0].id]: true }
      : {},
  );

  return (
    <Dialog.Root open={open} onOpenChange={onOpenChange}>
      <Dialog.Portal>
        <Dialog.Overlay className="fixed inset-0 z-[9998] bg-black/50 transition-opacity duration-300 ease-out data-[state=closed]:opacity-0 data-[state=open]:opacity-100" />
        <Dialog.Content
          className={cn(
            "fixed z-[9999] border bg-white font-poppins shadow-xl outline-none",
            resolvedDirection === "right"
              ? "right-3 top-3 bottom-3 flex h-auto w-[80vw] max-w-[1080px] flex-col rounded-2xl border transition-transform duration-300 ease-out will-change-transform data-[state=closed]:translate-x-full data-[state=open]:translate-x-0"
              : "bottom-0 left-0 flex h-[85vh] w-full flex-col rounded-t-[16px] border-t transition-transform duration-300 ease-out will-change-transform data-[state=closed]:translate-y-full data-[state=open]:translate-y-0",
          )}
        >
          <div className="flex items-start justify-between p-4 pb-[0px]">
            <Dialog.Title className="text-[20px] font-[600] leading-[28px] text-[#111928]">
              {heading}
            </Dialog.Title>
            <Dialog.Close className="inline-flex size-8 items-center justify-center rounded-md border text-[#111111] hover:bg-slate-50">
              <X size={24} />
              <span className="sr-only">Close</span>
            </Dialog.Close>
          </div>

          <div className="min-h-0 flex-1 space-y-5 overflow-y-auto p-5">
            <div className="grid grid-cols-1 gap-3 md:grid-cols-4">
              <StatBox
                title="Average Score"
                value={formatDecimal(data.averageScore)}
                valueSuffix="CGPA"
                icon={<ClipboardText size="24px" color="#6962AC" />}
              />
              <StatBox
                title="Total Evaluations"
                value={data.totalEvaluations}
                icon={<FileText size="24px" color="#0694A2" />}
              />
              <StatBox
                title="Attempted"
                value={data.attemptedEvaluations}
                icon={<CheckSquareOffset size="24px" color="#0E9F6E" />}
              />
              <StatBox
                title="Upcoming"
                value={data.upcomingEvaluations}
                icon={<CalendarDots size="24px" color="#3F83F8" />}
              />
            </div>

            <RichContent
              value={data.evaluationRules}
              className="text-[14px] leading-[20px] text-[#4B5563] [&_a]:underline [&_ol]:list-decimal [&_ol]:pl-5 [&_p]:mb-3 [&_p:last-child]:mb-0 [&_ul]:list-disc [&_ul]:pl-5"
            />

            <div className="space-y-[20px]">
              {data.evaluationDetails.map((detail) => {
                const isOpen = openAccordions[detail.id] ?? false;
                return (
                  <div
                    key={detail.id}
                    className="overflow-hidden rounded-[8px] border border-[#E5E7EB] bg-white"
                  >
                    <EvaluationSummaryRow
                      title={detail.title}
                      finalWeightage={detail.finalWeightage}
                      finalStatus={detail.finalStatus}
                      finalScore={detail.finalScore}
                      onClick={() =>
                        setOpenAccordions((prev) => ({
                          ...prev,
                          [detail.id]: !isOpen,
                        }))
                      }
                      isExpanded={isOpen}
                    />

                    {isOpen ? (
                      <div className="border-t border-[#E5E7EB] bg-[#F9FAFB] p-4">
                        <div className="mb-3 text-[14px] font-[400] leading-[20px] text-[#4B5563]">
                          {detail.rules}
                        </div>
                        <div className="overflow-hidden rounded-[8px] border border-[#E5E7EB] bg-white">
                          <div className="grid grid-cols-[minmax(0,1fr)_300px_170px] gap-2 bg-[#F9FAFB] px-7 py-2 text-[12px] font-[500] uppercase tracking-[0.24px] text-[#4B5563]">
                            <p>Attempts</p>
                            <p className="text-center">Date</p>
                            <p className="text-center">Score</p>
                          </div>
                          {detail.evaluations.map((evaluation) => (
                            <div
                              key={evaluation.id}
                              className="grid grid-cols-[minmax(0,1fr)_300px_170px] items-center gap-2 border-t border-[#E5E7EB] px-7 py-[18px]"
                            >
                              <p className="truncate text-[14px] font-[500] leading-[20px] text-[#6962AC]">
                                {evaluation.title}
                              </p>
                              <p className="text-center text-[14px] font-[500] leading-[20px] text-[#4B5563]">
                                {formatDateTime(evaluation.schedule)}
                              </p>
                              <p className="text-center text-[28px] text-[0px] font-[500] leading-none text-[#4B5563]">
                                <span className="text-[14px] leading-[20px]">
                                  {toScoreLabel(
                                    evaluation.evaluationStatus,
                                    evaluation.score,
                                  )}
                                </span>
                              </p>
                            </div>
                          ))}
                        </div>
                      </div>
                    ) : null}
                  </div>
                );
              })}
            </div>
          </div>
        </Dialog.Content>
      </Dialog.Portal>
    </Dialog.Root>
  );
}

import { CaretDown } from "@phosphor-icons/react";

import type { EvaluationStatus } from "./types";
import { StatusPill, formatDecimal } from "./evaluation-card-preview";

const cn = (...classes: Array<string | false | null | undefined>) => classes.filter(Boolean).join(" ");

type EvaluationSummaryRowProps = {
  title: string;
  finalWeightage: number;
  finalStatus: EvaluationStatus;
  finalScore: number | null;
  onClick?: () => void;
  isExpanded?: boolean;
  showChevron?: boolean;
  className?: string;
};

export function EvaluationSummaryRow({
  title,
  finalWeightage,
  finalStatus,
  finalScore,
  onClick,
  isExpanded = false,
  showChevron = true,
  className,
}: EvaluationSummaryRowProps) {
  const Container = onClick ? "button" : "div";

  return (
    <Container
      type={onClick ? "button" : undefined}
      className={cn(
        "relative grid w-full grid-cols-3 items-center gap-2 bg-white px-4 py-4 text-left",
        showChevron && "pr-10",
        onClick && "hover:bg-[#FAFAFA]",
        className,
      )}
      onClick={onClick}
    >
      <p className="truncate text-[16px] font-[600] leading-[24px] text-[#000000]">
        {title}
      </p>
      <p className="text-center text-[14px] font-[500] leading-[20px] text-[#374151]">
        {formatDecimal(finalWeightage)}% weightage
      </p>
      <div className="flex justify-end">
        <StatusPill
          status={finalStatus}
          score={finalScore}
          completedTemplate="cgpa-out-of-10"
          className="px-4 py-1 text-[14px] font-[600] normal-case"
        />
      </div>
      {showChevron ? (
        <CaretDown
          size={16}
          className={cn(
            "absolute right-4 top-1/2 -translate-y-1/2 text-[#6B7280] transition-transform",
            isExpanded && "rotate-180",
          )}
        />
      ) : null}
    </Container>
  );
}

"use client"

import ReactMarkdown from "react-markdown"
import rehypeRaw from "rehype-raw"
import rehypeSanitize, { defaultSchema } from "rehype-sanitize"
import remarkGfm from "remark-gfm"
import type { Options as SanitizeOptions } from "rehype-sanitize"

const cn = (...classes: Array<string | false | null | undefined>) => classes.filter(Boolean).join(" ")

type RichContentProps = {
  value: string
  className?: string
}

const sanitizeSchema: SanitizeOptions = {
  ...defaultSchema,
  tagNames: [...(defaultSchema.tagNames ?? []), "video"],
  attributes: {
    ...(defaultSchema.attributes ?? {}),
    video: [
      "src",
      "controls",
      "poster",
      "preload",
      "playsInline",
      "muted",
      "loop",
      "width",
      "height",
    ],
    source: [...(defaultSchema.attributes?.source ?? []), "src", "type"],
  },
}

function decodeMarkdownPayload(content: string): string {
  if (!content) return ""

  const normalizedContent = content
    .replace(/\\r\\n/g, "\n")
    .replace(/\\n/g, "\n")
    .replace(/\\t/g, "\t")

  if (normalizedContent.includes("&lt;") || normalizedContent.includes("&gt;")) {
    const parser = new DOMParser()
    const decoded = parser
      .parseFromString(normalizedContent, "text/html")
      .documentElement.textContent
    return decoded ?? normalizedContent
  }

  return normalizedContent
}

export function RichContent({ value, className }: RichContentProps) {
  if (!value.trim()) return null

  return (
    <div
      className={cn(
        "min-w-0 max-w-full break-words [&_a]:break-all [&_code]:break-all [&_li]:min-w-0 [&_li]:whitespace-pre-wrap [&_ol]:min-w-0 [&_p]:min-w-0 [&_p]:whitespace-pre-wrap [&_ul]:min-w-0",
        className,
      )}
    >
      <ReactMarkdown
        remarkPlugins={[remarkGfm]}
        rehypePlugins={[rehypeRaw, [rehypeSanitize, sanitizeSchema]]}
      >
        {decodeMarkdownPayload(value)}
      </ReactMarkdown>
    </div>
  )
}

type CardCtaButtonProps = {
  text: string;
  onClick?: () => void;
  theme?: "yellow" | "red" | "purple";
  fullWidth?: boolean;
  className?: string;
};

const THEME_CLASSES = {
  yellow: "bg-[#EF8833] text-[#fff] hover:bg-[#DC7A2D]",
  red: "bg-[#EF4444] text-white hover:bg-[#DC2626]",
  purple: "bg-[#6962AC] text-white hover:bg-[#5B5596]",
} as const;

export function CardCtaButton({
  text,
  onClick,
  theme = "yellow",
  fullWidth = false,
  className = "",
}: CardCtaButtonProps) {
  return (
    <button
      type="button"
      onClick={onClick}
      className={`inline-flex min-w-0 max-w-full cursor-pointer items-center justify-center rounded-[8px] px-[16px] py-[8px] text-[14px] font-[500] leading-[20px] font-poppins transition-colors ${fullWidth ? "w-full" : ""} ${THEME_CLASSES[theme]} ${className}`.trim()}
    >
      <span className="min-w-0 max-w-full whitespace-normal break-words text-center">{text}</span>
    </button>
  );
}
